-- ============================================================================
-- Quiz Seed: Ruth (Chapters 1–4)
-- 3 difficulties × 4 chapters = 64 total questions
-- ============================================================================

-- ═══ Ruth Chapter 1 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Ruth', 1, 'kids', 1, 'Where did Naomi and her family go when there was a famine in Bethlehem?', 'The country of Moab', 'Egypt', 'Canaan', 'The city of Jericho', 'a', 'Ruth 1:1 — "A certain man of Beth-lehem-judah went to sojourn in the country of Moab, he, and his wife, and his two sons."'),
('Ruth', 1, 'kids', 2, 'What did Ruth say she would do when Naomi told her to go back to her own people?', 'Whither thou goest, I will go', 'I will stay until the harvest is over', 'I will find a new husband here', 'I will pray and then decide', 'a', 'Ruth 1:16 — "Ruth said, Intreat me not to leave thee, or to return from following after thee: for whither thou goest, I will go."'),
('Ruth', 1, 'kids', 3, 'What new name did Naomi ask people to call her when she returned to Bethlehem?', 'Mara, meaning bitter', 'Miriam, meaning beloved', 'Rahab, meaning blessed', 'Leah, meaning weary', 'a', 'Ruth 1:20 — "She said unto them, Call me not Naomi, call me Mara: for the Almighty hath dealt very bitterly with me."'),
-- Teens
('Ruth', 1, 'teens', 1, 'What were the names of Naomi''s two sons who married Moabite women?', 'Mahlon and Chilion', 'Boaz and Elijah', 'Elimelech and Salmon', 'Obed and Jesse', 'a', 'Ruth 1:2 — "The name of his two sons Mahlon and Chilion, Ephrathites of Beth-lehem-judah."'),
('Ruth', 1, 'teens', 2, 'What were the names of the two Moabite daughters-in-law whom Naomi urged to return to their mothers'' houses?', 'Orpah and Ruth', 'Leah and Rachel', 'Basemath and Mahalath', 'Judith and Adah', 'a', 'Ruth 1:4 — "They took them wives of the women of Moab; the name of the one was Orpah, and the name of the other Ruth."'),
('Ruth', 1, 'teens', 3, 'What did Orpah do when Naomi urged both daughters-in-law to return to their own people?', 'She kissed Naomi and returned to her people', 'She wept but stayed with Naomi', 'She refused to leave and went to Bethlehem', 'She went to find another husband in Moab', 'a', 'Ruth 1:14 — "Orpah kissed her mother in law; but Ruth clave unto her."'),
('Ruth', 1, 'teens', 4, 'Ruth declared she would follow Naomi''s God. Which God did she name as the one she would serve?', 'Thy God shall be my God', 'The LORD God of Abraham', 'The God of the Hebrews', 'The God of all the earth', 'a', 'Ruth 1:16 — "Thy people shall be my people, and thy God my God."'),
('Ruth', 1, 'teens', 5, 'At what time of year did Naomi and Ruth arrive back in Bethlehem?', 'The beginning of barley harvest', 'The feast of firstfruits', 'The end of the wheat harvest', 'The season of the early rains', 'a', 'Ruth 1:22 — "They came to Beth-lehem in the beginning of barley harvest."'),
-- Adults
('Ruth', 1, 'adults', 1, 'What was the name of Naomi''s husband who died in the land of Moab?', 'Elimelech', 'Mahlon', 'Salmon', 'Boaz', 'a', 'Ruth 1:3 — "Elimelech Naomi''s husband died; and she was left, and her two sons."'),
('Ruth', 1, 'adults', 2, 'What theological argument did Naomi use to persuade her daughters-in-law to return to Moab?', 'The hand of the LORD had gone out against her and she had no more sons for them to marry', 'God had commanded her to send them away', 'They would find no favour with the God of Israel', 'She could not provide for them in Bethlehem', 'a', 'Ruth 1:13 — "It grieveth me much for your sakes that the hand of the LORD is gone out against me."'),
('Ruth', 1, 'adults', 3, 'What oath did Ruth swear to Naomi, and what did it signify about her commitment?', 'The LORD do so to me, and more also, if ought but death part thee and me', 'I swear by the gods of Moab that I will stay with thee', 'As the LORD liveth I will follow thee to the ends of the earth', 'I vow before heaven that thy people are my people forever', 'a', 'Ruth 1:17 — "The LORD do so to me, and more also, if ought but death part thee and me." This covenant oath invoked divine judgment on herself if she broke her promise.'),
('Ruth', 1, 'adults', 4, 'What does the name Mara mean, and why did Naomi request it?', 'Bitter, because the Almighty had dealt very bitterly with her', 'Sorrowful, because she had lost her children', 'Empty, because she had returned with nothing', 'Forsaken, because God had left her', 'a', 'Ruth 1:20 — "Call me Mara: for the Almighty hath dealt very bitterly with me." The Hebrew root marar means bitter.'),
('Ruth', 1, 'adults', 5, 'How did Naomi describe what the LORD had done to her when she returned to Bethlehem?', 'I went out full and the LORD hath brought me home again empty', 'The LORD stripped me of all I possessed', 'God turned His face from me in the land of Moab', 'The Almighty hid His hand against my household', 'a', 'Ruth 1:21 — "I went out full, and the LORD hath brought me home again empty: why then call ye me Naomi, seeing the LORD hath testified against me, and the Almighty hath afflicted me?"'),
('Ruth', 1, 'adults', 6, 'What does Naomi''s reference to "the Almighty" (Shaddai) twice in Ruth 1:20-21 reveal about her theology?', 'She acknowledged God''s sovereign power over her suffering while still addressing Him by covenant name', 'She had abandoned the covenant name LORD and replaced it with a pagan title', 'She was blaming fate rather than a personal God', 'She was comparing her suffering to Job''s and citing the same divine attribute', 'a', 'Ruth 1:20-21 — "The Almighty hath dealt very bitterly with me...the Almighty hath afflicted me." El Shaddai emphasises God''s sovereign power; her use of it shows she still attributed her circumstances to the hand of a personal, powerful God.'),
('Ruth', 1, 'adults', 7, 'How does Ruth''s declaration in Ruth 1:16-17 function as a formal covenant pledge, and what categories does it cover?', 'It covers geography (whither thou goest), community (thy people), religion (thy God), death (where thou diest), and burial (where thou art buried) — an exhaustive covenantal commitment', 'It is a personal emotional promise covering only her loyalty during Naomi''s lifetime', 'It is a prayer addressed to God rather than a pledge to Naomi', 'It covers only the religious commitment, modelled on Abraham''s call', 'a', 'Ruth 1:16-17 — "Whither thou goest, I will go; and where thou lodgest, I will lodge: thy people shall be my people, and thy God my God: Where thou diest, will I die, and there will I be buried." The pledge spans every dimension of life and death.'),
('Ruth', 1, 'adults', 8, 'What is the literary and theological significance of the book of Ruth being set "in the days when the judges ruled" (Ruth 1:1)?', 'It presents a story of faithful covenant love (hesed) as a counter-narrative to the apostasy and violence of the judges period', 'It simply dates the narrative for historical accuracy', 'It shows that not all Israelites were unfaithful during the judges era', 'It explains why the Moabites were willing to interact with Israel during this period', 'a', 'Ruth 1:1 — "Now it came to pass in the days when the judges ruled." The book of Judges ends in moral chaos; Ruth deliberately opens in the same era to contrast covenant faithfulness (hesed) with widespread unfaithfulness, ultimately pointing toward David and the Davidic line.');

-- ═══ Ruth Chapter 2 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Ruth', 2, 'kids', 1, 'What was Ruth doing in the field when Boaz first noticed her?', 'Gleaning grain left behind by the reapers', 'Selling water to the workers', 'Bringing food to the reapers', 'Helping to bind sheaves', 'a', 'Ruth 2:3 — "She went, and came, and gleaned in the field after the reapers."'),
('Ruth', 2, 'kids', 2, 'Who was Boaz related to?', 'He was a kinsman of Naomi''s husband Elimelech', 'He was Ruth''s uncle from Moab', 'He was the brother of the judge of Bethlehem', 'He was Naomi''s brother', 'a', 'Ruth 2:1 — "Naomi had a kinsman of her husband''s, a mighty man of wealth, of the family of Elimelech; and his name was Boaz."'),
('Ruth', 2, 'kids', 3, 'What food did Boaz invite Ruth to eat at mealtime?', 'Bread and parched corn dipped in vinegar', 'Roasted lamb and figs', 'Barley cakes and honey', 'Bread and olive oil', 'a', 'Ruth 2:14 — "Boaz said unto her, At mealtime come thou hither, and eat of the bread, and dip thy morsel in the vinegar. And she sat beside the reapers: and he reached her parched corn."'),
-- Teens
('Ruth', 2, 'teens', 1, 'What did Boaz say to his reapers he had heard about Ruth?', 'All the city of my people doth know that thou art a virtuous woman', 'She is faithful and works harder than the women of Israel', 'She left her own country to care for her mother-in-law after her husband died', 'She has prayed to the God of Israel and He will reward her', 'a', 'Ruth 2:11 — "Boaz answered and said unto her, It hath fully been shewed me, all that thou hast done unto thy mother in law since the death of thine husband: and how thou hast left thy father and thy mother, and the land of thy nativity, and art come unto a people which thou knewest not heretofore."'),
('Ruth', 2, 'teens', 2, 'What blessing did Boaz speak over Ruth regarding the LORD?', 'The LORD recompense thy work, and a full reward be given thee of the LORD God of Israel, under whose wings thou art come to trust', 'May the LORD bless thy going out and thy coming in from this day forth', 'The LORD shall be thy shepherd and thy portion for ever', 'May God repay thee double for thy kindness to Naomi', 'a', 'Ruth 2:12 — "The LORD recompense thy work, and a full reward be given thee of the LORD God of Israel, under whose wings thou art come to trust."'),
('Ruth', 2, 'teens', 3, 'What secret instructions did Boaz give his young men regarding Ruth?', 'Let fall also some of the handfuls on purpose for her and leave them so she may glean them', 'Give her a full share of the harvest wage every day', 'Allow her to glean among the bound sheaves', 'Never rebuke her and give her water when she is thirsty', 'a', 'Ruth 2:16 — "Let fall also some of the handfuls of purpose for her, and leave them, that she may glean them, and rebuke her not."'),
('Ruth', 2, 'teens', 4, 'How much barley did Ruth glean in her first day in Boaz''s field?', 'About an ephah of barley', 'About a homer of barley', 'Three omers of barley', 'Half a bushel of wheat and barley', 'a', 'Ruth 2:17 — "She gleaned in the field until even, and beat out that she had gleaned: and it was about an ephah of barley."'),
('Ruth', 2, 'teens', 5, 'What did Naomi tell Ruth about Boaz when she heard whose field Ruth had gleaned in?', 'The man is near of kin unto us, one of our next kinsmen', 'He is a wealthy man but will not help the poor', 'He is the brother of Elimelech and your kinsman-redeemer', 'He is a man of God who will provide for the widow and the stranger', 'a', 'Ruth 2:20 — "Naomi said unto her daughter in law, The man is near of kin unto us, one of our next kinsmen."'),
-- Adults
('Ruth', 2, 'adults', 1, 'What does Boaz''s greeting to his reapers — "The LORD be with you" — and their reply "The LORD bless thee" reveal about the spiritual atmosphere of his household?', 'It portrays Boaz as a godly landowner whose workplace was permeated with covenant blessing and reverence for the LORD', 'It was a standard Israelite business greeting with no particular spiritual meaning', 'It shows the reapers were Levites performing a religious duty', 'It indicates the harvest was taking place during a religious festival', 'a', 'Ruth 2:4 — "And, behold, Boaz came from Beth-lehem, and said unto the reapers, The LORD be with you. And they answered him, The LORD bless thee." The exchange establishes Boaz''s character before he speaks to Ruth.'),
('Ruth', 2, 'adults', 2, 'What question did Boaz ask his servant about Ruth, and what did the servant''s answer reveal?', 'Whose damsel is this? The servant answered she is the Moabitish damsel that came back with Naomi and asked to glean', 'Is this woman an Israelite? The servant answered she is a foreigner from Moab', 'Why does she glean here? The servant said Naomi sent her to learn the harvest customs', 'How long has she worked? The servant answered she came with the morning reapers', 'a', 'Ruth 2:5-7 — "Boaz said unto his servant...Whose damsel is this? And the servant...answered and said, It is the Moabitish damsel that came back with Naomi out of the country of Moab: And she said, I pray you, let me glean."'),
('Ruth', 2, 'adults', 3, 'What specific privileges did Boaz grant Ruth that went beyond the legal gleaning rights of the Law?', 'He told her to glean among the sheaves themselves, drink from his vessels, and commanded the men not to touch her', 'He gave her a daily wage equal to the hired workers', 'He appointed her as overseer of the women workers', 'He granted her full Israelite citizenship in his household', 'a', 'Ruth 2:8-9,15-16 — "Abide here fast by my maidens...have I not charged the young men that they shall not touch thee?...Let fall also some of the handfuls of purpose for her." These privileges exceeded the gleaning law of Leviticus 19:9-10.'),
('Ruth', 2, 'adults', 4, 'What does Ruth''s response "Why have I found grace in thine eyes, that thou shouldest take knowledge of me, seeing I am a stranger?" reveal about her self-understanding?', 'She recognised her social position as a foreign widow and was genuinely humbled by undeserved favour', 'She was testing Boaz to see if his kindness was genuine', 'She was following Naomi''s instructions to appear humble before Boaz', 'She was legally asserting her right to glean under Mosaic law', 'a', 'Ruth 2:10 — "Then she fell on her face, and bowed herself to the ground, and said unto him, Why have I found grace in thine eyes, that thou shouldest take knowledge of me, seeing I am a stranger?" Her question reflects genuine humility and awareness of her outsider status.'),
('Ruth', 2, 'adults', 5, 'How does Boaz''s blessing in Ruth 2:12 — "under whose wings thou art come to trust" — connect to Ruth''s later request in Ruth 3:9?', 'Ruth uses the same wing imagery when she asks Boaz to spread his skirt over her, linking his earlier blessing to the kinsman-redeemer role he is being asked to fulfil', 'The wing image appears only in chapter 2 as a spiritual metaphor with no narrative continuation', 'Ruth''s request in chapter 3 uses different imagery to show she did not understand Boaz''s blessing', 'The connection is coincidental since wing language was common in Hebrew blessings', 'a', 'Ruth 2:12 — "under whose wings thou art come to trust" and Ruth 3:9 — "spread therefore thy skirt over thine handmaid" use the same Hebrew root (kanaf — wing/skirt), showing Ruth invites Boaz to be the human instrument of the divine protection he blessed her with.'),
('Ruth', 2, 'adults', 6, 'What is the legal basis for gleaning described elsewhere in the Torah that Ruth was exercising, and how did Boaz exceed it?', 'Leviticus 19:9-10 and Deuteronomy 24:19 mandated leaving corners and fallen grain for the poor and stranger; Boaz added deliberate handfuls and access to bound sheaves', 'Exodus 22:21 gave foreigners gleaning rights in all fields; Boaz added water and food rights', 'Numbers 18:28 allocated a tithe portion for Levites and strangers; Boaz extended it to widows', 'Deuteronomy 14:29 gave the stranger and widow rights to tithes; Boaz granted harvest access instead', 'a', 'Leviticus 19:9-10 — "Thou shalt not wholly reap the corners of thy field...thou shalt leave them for the poor and stranger." Boaz instructed in Ruth 2:16: "Let fall also some of the handfuls of purpose for her," exceeding the minimum legal requirement.'),
('Ruth', 2, 'adults', 7, 'What does Naomi''s exclamation "Blessed be he of the LORD, who hath not left off his kindness to the living and to the dead" suggest about her interpretation of events?', 'She saw Boaz''s kindness as God''s providential hesed continuing toward Elimelech''s family even after his death', 'She was simply praising Boaz for his generosity without any theological meaning', 'She was comparing Boaz''s kindness to the kindness of the dead sons', 'She believed Elimelech had sent Boaz as a messenger from beyond the grave', 'a', 'Ruth 2:20 — "Blessed be he of the LORD, who hath not left off his kindness to the living and to the dead." Naomi sees Boaz''s kindness as the LORD''s own hesed (covenant loyalty) flowing through a human agent, extending care even to Elimelech and the dead sons.'),
('Ruth', 2, 'adults', 8, 'How does the opening description of Boaz in Ruth 2:1 as "a mighty man of wealth" (gibbor hayil) compare to Ruth''s description in Ruth 3:11 as "a virtuous woman" (eshet hayil)?', 'Both use the same Hebrew root hayil (strength/valor/worth), presenting Boaz and Ruth as matched in character — a man and woman of noble excellence', 'The terms are unrelated; gibbor means warrior while eshet hayil means obedient wife', 'Boaz''s title refers only to financial wealth while Ruth''s refers only to moral purity', 'The comparison was intentional to suggest Ruth was Boaz''s social equal despite being a foreigner', 'a', 'Ruth 2:1 — "gibbor hayil" (mighty man of valor/worth) and Ruth 3:11 — "eshet hayil" (woman of valor/worth) share the root hayil, a deliberate literary pairing establishing Boaz and Ruth as equal in character and setting up their union as fitting.');

-- ═══ Ruth Chapter 3 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Ruth', 3, 'kids', 1, 'Where did Naomi send Ruth to meet Boaz at night?', 'The threshing floor', 'The city gate', 'The well outside the city', 'Boaz''s house', 'a', 'Ruth 3:3 — "Wash thyself therefore, and anoint thee, and put thy raiment upon thee, and get thee down to the floor."'),
('Ruth', 3, 'kids', 2, 'What did Ruth do to Boaz when she found him sleeping at the threshing floor?', 'She uncovered his feet and lay down at them', 'She woke him up and gave him food', 'She sat beside him and waited for morning', 'She put her cloak over him while he slept', 'a', 'Ruth 3:7 — "She came softly, and uncovered his feet, and laid her down."'),
('Ruth', 3, 'kids', 3, 'What did Boaz tell Ruth he would do in the morning if the nearer kinsman would not redeem her?', 'As the LORD liveth, I will do the part of a kinsman to thee', 'He would ask the elders to decide', 'He would give her fields of her own', 'He would speak to Naomi first before making any promise', 'a', 'Ruth 3:13 — "As the LORD liveth, lie down until the morning...if he will not do the part of a kinsman to thee, then will I do the part of a kinsman to thee."'),
-- Teens
('Ruth', 3, 'teens', 1, 'What reason did Naomi give for seeking "rest" for Ruth through Boaz?', 'She said she would seek rest for Ruth so that it might be well with her, and that Boaz was a kinsman', 'She said the harvest season was ending and Ruth needed a permanent home', 'She said Ruth had earned rest by her faithful gleaning all season', 'She said God had told her in a dream to arrange the marriage', 'a', 'Ruth 3:1 — "My daughter, shall I not seek rest for thee, that it may be well with thee?"'),
('Ruth', 3, 'teens', 2, 'What request did Ruth make of Boaz when he woke at midnight and found her at his feet?', 'Spread thy skirt over thine handmaid; for thou art a near kinsman', 'Take me as thy wife and redeem Naomi''s land', 'Be a father to me as thou art of the family of Elimelech', 'Give me a place in thy household for Naomi''s sake', 'a', 'Ruth 3:9 — "She answered, I am Ruth thine handmaid: spread therefore thy skirt over thine handmaid; for thou art a near kinsman."'),
('Ruth', 3, 'teens', 3, 'What did Boaz say about Ruth''s character that all the city knew?', 'All the city of my people doth know that thou art a virtuous woman', 'The people of Bethlehem say thou art more loyal than any daughter of Israel', 'My servants have told me thou art a woman of great faith', 'The elders of the city testify that thou art worthy of redemption', 'a', 'Ruth 3:11 — "All the city of my people doth know that thou art a virtuous woman."'),
('Ruth', 3, 'teens', 4, 'Why did Boaz say he could not immediately act as kinsman-redeemer for Ruth?', 'There was a kinsman nearer than he who had the first right of redemption', 'He needed permission from the elders of the city first', 'He had to wait until the end of the barley harvest season', 'The law required three witnesses before a redemption could proceed', 'a', 'Ruth 3:12 — "And now it is true that I am thy near kinsman: howbeit there is a kinsman nearer than I."'),
('Ruth', 3, 'teens', 5, 'What did Boaz give Ruth to take back to Naomi before she left the threshing floor?', 'Six measures of barley', 'A new outer garment and two loaves of bread', 'Silver coins and a portion of the harvest', 'A jar of oil and grain for grinding', 'a', 'Ruth 3:15 — "Also he said, Bring the vail that thou hast upon thee, and hold it. And when she held it, he measured six measures of barley, and laid it on her: and she went into the city."'),
-- Adults
('Ruth', 3, 'adults', 1, 'What is the significance of Naomi''s instructions for Ruth to wash, anoint herself, and put on her raiment before going to the threshing floor?', 'These were the customary acts of a widow ending her mourning period and presenting herself for potential remarriage', 'They were Moabite ritual practices Ruth was familiar with from her homeland', 'They were required by Mosaic law before approaching a kinsman-redeemer', 'They were simply practical preparations to avoid being recognized in the dark', 'a', 'Ruth 3:3 — "Wash thyself therefore, and anoint thee, and put thy raiment upon thee." In the ancient Near East these acts signalled a transition from mourning to readiness for marriage, consistent with widows formally ending their period of grief.'),
('Ruth', 3, 'adults', 2, 'How does Ruth''s request for Boaz to "spread thy skirt" (kanaf) over her echo Boaz''s blessing in Ruth 2:12, and what does this connection imply?', 'Ruth turns Boaz''s blessing — that she had come under the LORD''s wings (kanaf) — into an invitation for Boaz himself to be the instrument of that divine protection through marriage', 'Ruth is quoting a legal formula for property transfer used in ancient Israelite courts', 'The term kanaf simply means a cloak in both verses and has no thematic connection', 'Ruth had memorised Boaz''s blessing and repeated it back as flattery', 'a', 'Ruth 2:12 — "under whose wings (kanaf) thou art come to trust" and Ruth 3:9 — "spread therefore thy skirt (kanaf) over thine handmaid." Same Hebrew word; Ruth''s request fulfils the shape of Boaz''s earlier prayer by inviting him to be its answer.'),
('Ruth', 3, 'adults', 3, 'What does Boaz mean when he says Ruth showed more kindness at the end than at the beginning by not going after young men?', 'Ruth chose the legal path of levirate-style redemption for Naomi''s family rather than pursuing a young man for personal happiness, demonstrating hesed toward the dead', 'Ruth had initially sought a younger husband but repented and returned to honour Naomi', 'Ruth refused Boaz''s reapers who had courted her throughout the harvest season', 'Boaz was comparing Ruth to Orpah who had pursued a second marriage in Moab', 'a', 'Ruth 3:10 — "Blessed be thou of the LORD, my daughter: for thou hast shewed more kindness in the latter end than at the beginning, inasmuch as thou followedst not young men, whether poor or rich." Ruth''s goal was to raise up the name of the dead through proper redemption, not personal romantic advantage.'),
('Ruth', 3, 'adults', 4, 'What does Boaz''s statement "Fear not; I will do to thee all that thou requirest" indicate about his moral character in the context of the threshing floor scene?', 'It shows his integrity — he immediately redirected the situation toward legal redemption rather than taking advantage of Ruth''s vulnerable position', 'It was a formal contractual oath binding him legally before witnesses', 'It indicated Boaz had already decided to marry Ruth regardless of the nearer kinsman', 'It was a reassurance that no one at the threshing floor had seen Ruth arrive', 'a', 'Ruth 3:11 — "And now, my daughter, fear not; I will do to thee all that thou requirest." Boaz''s response — addressing the legal obstacle, promising to act rightly, and sending Ruth home safely before dawn — demonstrates consistent moral integrity throughout the scene.'),
('Ruth', 3, 'adults', 5, 'Why did Boaz send Ruth away before dawn so that she would not be recognised, and what does this reveal about his concern?', 'He was protecting Ruth''s reputation so that no one would suspect immoral behaviour at the threshing floor', 'He wanted to complete the legal transaction first before Ruth was publicly associated with him', 'He was following threshing floor protocol that required all guests to leave before sunrise', 'He feared the nearer kinsman would hear of Ruth''s visit and claim her before Boaz could act', 'a', 'Ruth 3:14 — "She rose up before one could know another. And he said, Let it not be known that a woman came into the floor." Boaz''s care for Ruth''s reputation demonstrates that his actions throughout were governed by honour and protection of the vulnerable.'),
('Ruth', 3, 'adults', 6, 'What was the purpose of the six measures of barley Boaz sent with Ruth to Naomi?', 'It was a tangible pledge to Naomi that Boaz intended to act, so she would not go empty-handed', 'It was payment for Naomi''s counsel in arranging the meeting', 'It was legally required as a first-fruits offering before a redemption transaction', 'It was food provision for Ruth and Naomi until the legal case was resolved', 'a', 'Ruth 3:17 — "He gave me these six measures of barley; for he said to me, Go not empty unto thy mother in law." Boaz''s gift was a deliberate reversal of Naomi''s lament in Ruth 1:21 — "the LORD hath brought me home again empty" — now she would not be empty again.'),
('Ruth', 3, 'adults', 7, 'What does Naomi''s counsel "Sit still, my daughter, until thou know how the matter will fall" reveal about her theological outlook after the events of the night?', 'She trusted that Boaz, as a man of integrity, would not rest until the matter was resolved that day — a confidence rooted in her knowledge of his character and the LORD''s providence', 'She was advising Ruth to wait patiently because legal proceedings in Israel took many days', 'She was uncertain whether Boaz would follow through and counselled caution', 'She was instructing Ruth to pray and wait for a divine sign', 'a', 'Ruth 3:18 — "Then said she, Sit still, my daughter, until thou know how the matter will fall: for the man will not be in rest, until he have finished the thing this day." Naomi''s confidence in Boaz reflects her restored trust that God''s hesed is operating through him.'),
('Ruth', 3, 'adults', 8, 'How does the kinsman-redeemer (goel) institution function in Israelite law, and what specific obligations would it entail for Boaz?', 'The goel was the nearest male relative responsible for redeeming family land, marrying a childless widow to continue the family line, and protecting the family''s inheritance within Israel', 'The goel was the city treasurer who managed widows'' financial affairs under the elders'' supervision', 'The goel was a volunteer who could redeem any widow in the tribe, unrelated to family structure', 'The goel institution was primarily about freeing slaves and had only secondary application to land and widows', 'a', 'Ruth 3:12-13 — "I am thy near kinsman: howbeit there is a kinsman nearer than I." The goel (redeemer) institution is rooted in Leviticus 25:25 (land redemption), Deuteronomy 25:5-10 (levirate duty), and Numbers 35:19 (blood avenger). Boaz''s redemption of Ruth would involve purchasing Elimelech''s land and raising up the dead man''s name through offspring.');

-- ═══ Ruth Chapter 4 ═══
INSERT INTO chapter_quizzes (book_name, chapter_number, difficulty, question_number, question, option_a, option_b, option_c, option_d, correct_answer, explanation) VALUES
-- Kids
('Ruth', 4, 'kids', 1, 'Where did Boaz go to arrange to marry Ruth in front of witnesses?', 'The gate of the city', 'The threshing floor', 'The temple in Jerusalem', 'The well in the centre of town', 'a', 'Ruth 4:1 — "Then went Boaz up to the gate, and sat him down there: and, behold, the kinsman of whom Boaz spake came by."'),
('Ruth', 4, 'kids', 2, 'What was the name of the baby boy that Ruth and Boaz had?', 'Obed', 'Jesse', 'David', 'Salmon', 'a', 'Ruth 4:17 — "The women her neighbours gave it a name, saying, There is a son born to Naomi; and they called his name Obed."'),
('Ruth', 4, 'kids', 3, 'What did the women of Bethlehem say Ruth was worth to Naomi?', 'Better to thee than seven sons', 'A blessing above all women', 'More precious than silver and gold', 'Worthy of a place among the judges', 'a', 'Ruth 4:15 — "He shall be unto thee a restorer of thy life, and a nourisher of thine old age: for thy daughter in law, which loveth thee, which is better to thee than seven sons, hath born him."'),
-- Teens
('Ruth', 4, 'teens', 1, 'What custom did the nearer kinsman use to confirm that he gave up his right of redemption?', 'He plucked off his shoe and gave it to Boaz', 'He broke a clay tablet in front of the elders', 'He tore his outer garment and gave half to Boaz', 'He wrote his name in dust at the gate and wiped it away', 'a', 'Ruth 4:7-8 — "Now this was the manner in former time in Israel concerning redeeming...a man plucked off his shoe, and gave it to his neighbour...Therefore the kinsman said unto Boaz, Buy it for thee. So he drew off his shoe."'),
('Ruth', 4, 'teens', 2, 'Why did the nearer kinsman refuse to redeem Naomi''s land after initially agreeing?', 'He feared marrying Ruth would mar his own inheritance', 'He had already promised his inheritance to another family', 'He said he did not have the silver to purchase the land', 'He was afraid the elders would not approve the transaction', 'a', 'Ruth 4:6 — "The kinsman said, I cannot redeem it for myself, lest I mar mine own inheritance: redeem thou my right to thyself; for I cannot redeem it."'),
('Ruth', 4, 'teens', 3, 'How many witnesses did Boaz call to observe the redemption transaction at the gate?', 'Ten men of the elders of the city', 'Seven priests and three elders', 'The whole assembly of the men of Bethlehem', 'The judge of the city and two witnesses', 'a', 'Ruth 4:2 — "He took ten men of the elders of the city, and said, Sit ye down here. And they sat down."'),
('Ruth', 4, 'teens', 4, 'What blessing did the elders and people pronounce over Ruth when Boaz declared he was taking her as his wife?', 'The LORD make the woman that is come into thine house like Rachel and like Leah', 'May the God of Israel bless thy household as He blessed Abraham', 'Be fruitful and multiply and fill the land of Israel', 'May thy children be mighty in Israel like the sons of Jacob', 'a', 'Ruth 4:11 — "The LORD make the woman that is come into thine house like Rachel and like Leah, which two did build the house of Israel."'),
('Ruth', 4, 'teens', 5, 'Whose famous lineage does the end of Ruth 4 trace through Obed?', 'King David''s lineage through Perez, son of Judah', 'Solomon''s lineage through the tribe of Benjamin', 'Samuel the prophet''s lineage through Ephraim', 'The priestly line through Aaron and Levi', 'a', 'Ruth 4:17-22 — "They called his name Obed: he is the father of Jesse, the father of David." The genealogy traces back to Perez, son of Judah (v.18), connecting to the Davidic line.'),
-- Adults
('Ruth', 4, 'adults', 1, 'How did Boaz present the redemption case to the nearer kinsman at the gate, and why did he initially withhold the information about Ruth?', 'He first mentioned only the land of Naomi, allowing the kinsman to agree, then revealed the obligation to take Ruth and raise up the dead man''s name — which changed the financial calculation', 'He presented the full terms immediately but gave the kinsman three days to decide', 'He asked the kinsman about Ruth first, then mentioned the land as an added incentive', 'He appealed to the elders to compel the kinsman before offering him the choice', 'a', 'Ruth 4:3-5 — Boaz first said "Naomi...selleth a parcel of land" (v.3) and the kinsman agreed (v.4). Then Boaz added "What day thou buyest the field...thou must buy it also of Ruth...to raise up the name of the dead" (v.5), which caused the kinsman to reverse his decision.'),
('Ruth', 4, 'adults', 2, 'What was the kinsman''s precise reason for refusing redemption, and what does it reveal about his priorities?', 'He said it would mar his own inheritance — acquiring Ruth''s son would divide his estate among multiple heirs at the expense of his existing family line', 'He said he was already bound to another woman and could not take a second wife under the law', 'He said the land was not worth its purchase price and would be a financial loss', 'He said he was too old to fulfil the levirate duty and wished to spare Ruth the hardship', 'a', 'Ruth 4:6 — "I cannot redeem it for myself, lest I mar mine own inheritance." If he redeemed the land but Ruth''s son would eventually inherit it in Elimelech''s name, the kinsman''s own estate would be reduced without long-term benefit to his own line.'),
('Ruth', 4, 'adults', 3, 'The sandal custom in Ruth 4:7 is explained as "the manner in former time in Israel." What does this parenthetical explanation suggest about the narrator''s audience and the date of composition?', 'It implies the author was writing at a later period when the sandal-exchange custom had fallen out of use and needed explanation for readers', 'It was inserted by a later editor who misunderstood the original transaction', 'It indicates the author was not an Israelite and was explaining foreign customs', 'It shows the custom was newly established and the author wanted to record its origin', 'a', 'Ruth 4:7 — "Now this was the manner in former time in Israel concerning redeeming...for to confirm all things; a man plucked off his shoe." The editorial aside indicates the practice was archaic by the time of writing, suggesting a later composition date while preserving authentic early custom.'),
('Ruth', 4, 'adults', 4, 'What is the theological significance of the blessing comparing Ruth to Rachel and Leah, and adding the prayer about Perez?', 'It places Ruth in the founding lineage of the twelve tribes and explicitly invokes the Perez-Judah line through which the Davidic promise would run', 'It is a general fertility blessing with no specific messianic or royal significance', 'It compares Ruth to the matriarchs to honour her Moabite heritage', 'The blessing was formulaic and spoken at all Israelite marriages without special meaning', 'a', 'Ruth 4:11-12 — "Like Rachel and like Leah, which two did build the house of Israel...and let thy house be like the house of Pharez, whom Tamar bare unto Judah." The Perez reference is striking: Tamar was also a woman outside Israel whose initiative continued the covenant line, and Perez is the direct ancestor listed in Ruth 4:18.'),
('Ruth', 4, 'adults', 5, 'What is the meaning of the name Obed, and how does it function in the narrative resolution?', 'Obed means servant or worshipper, and his birth restores Naomi''s line — he becomes servant/nourisher of her old age, reversing her emptiness', 'Obed means redeemed, celebrating the completion of the kinsman-redeemer transaction', 'Obed means son of the gate, commemorating where his father''s redemption was completed', 'Obed means gift of God, paralleling Isaac whose name also celebrated divine provision', 'a', 'Ruth 4:17 — "There is a son born to Naomi; and they called his name Obed." The name Obed (eved — servant) ties to verse 15''s promise that he will be "a nourisher of thine old age"; the women''s declaration "a son born to Naomi" shows Obed restores Naomi''s family line.'),
('Ruth', 4, 'adults', 6, 'How does the book of Ruth''s genealogy in Ruth 4:18-22 connect to Matthew 1 and what is its messianic significance?', 'The genealogy Perez–Hezron–Ram–Amminadab–Nahshon–Salmon–Boaz–Obed–Jesse–David is reproduced in Matthew 1:3-6 as part of the lineage of Jesus Christ, placing Ruth directly in the Messianic line', 'The genealogy ends with David and has no explicit New Testament connection', 'Matthew 1 uses a different genealogy that bypasses Ruth and goes directly from Salmon to Jesse', 'The connection to Matthew 1 is only symbolic and the names do not match exactly', 'a', 'Ruth 4:18-22 — "Pharez begat Hezron...and Salmon begat Boaz...and Boaz begat Obed...and Jesse begat David." Matthew 1:5-6 — "Salmon begat Booz of Rachab; and Booz begat Obed of Ruth; and Obed begat Jesse; And Jesse begat David the king." Ruth is explicitly named in Christ''s genealogy.'),
('Ruth', 4, 'adults', 7, 'What is the theological theme of hesed (covenant lovingkindness) and how is it woven through all four chapters of Ruth, culminating in chapter 4?', 'Hesed appears in Ruth 1:8 (Naomi''s blessing), 2:20 (Boaz''s kindness as God''s hesed), and 3:10 (Ruth''s hesed in seeking redemption); chapter 4 shows hesed completed in Boaz''s legal action, reversing every loss in chapter 1', 'Hesed appears only in Ruth 2:20 and is a single description of Boaz''s character without structural significance', 'Hesed is a minor theme overshadowed by the legal redemption narrative which is the book''s central focus', 'The theme of hesed is introduced in chapter 3 and concluded in chapter 4 without preparation in chapters 1-2', 'a', 'Ruth 1:8 — "The LORD deal kindly (hesed) with you"; 2:20 — "who hath not left off his kindness (hesed) to the living and to the dead"; 3:10 — "thou hast shewed more kindness (hesed) in the latter end than at the beginning." Chapter 4''s redemption is the narrative fulfilment of all three expressions of hesed.'),
('Ruth', 4, 'adults', 8, 'Why is it theologically significant that a Moabite woman — from a nation excluded in Deuteronomy 23:3 — appears in the lineage of David and ultimately of Christ?', 'It demonstrates that God''s redemptive purposes transcend national boundaries, that genuine faith and hesed qualify a foreigner for covenant inclusion, and that grace operates beyond the letter of the exclusion law', 'It shows the Deuteronomy 23:3 exclusion was only temporary and expired after one generation', 'It reveals that the exclusion in Deuteronomy 23:3 applied only to male Moabites entering the assembly, not to women', 'It was an oversight in the original law that later scribes corrected by including Ruth in the canon', 'a', 'Deuteronomy 23:3 — "An Ammonite or Moabite shall not enter into the congregation of the LORD; even to their tenth generation." Yet Ruth 4:17-22 and Matthew 1:5 place Ruth directly in the Davidic and Messianic line. Ruth''s inclusion — grounded in her hesed, faith, and covenant commitment — points to the wideness of God''s redemptive grace that is fully revealed in Christ.');
